  function buildSummary(weather: any, headingBearing: number) {
    const parts = [];
    const wind = weather.current.windSpeed;
    const windDir = weather.current.windDirection;
    const angleDiff = Math.abs(((windDir - headingBearing + 180) % 360) - 180);

    // Wind description
    if (wind < 5) parts.push('Calm winds');
