      bearing: dir.bearing,
      samplePoint: samplePoints[i],
      score,
      rating: getRating(score),
      summary: buildSummary(weather, dir.bearing),
      conditions: weather.current
    };
  });

  return { origin: { lat, lon }, directions: results };
}
