6-06-19T11:45:45.812Z","completedAt":null}}},{"name":"upload_text_asset","input":{"content":"
/* ===== Reset & Base ===== */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

:root {
  --bg-dark: #0a1628;
  --bg-panel: rgba(10, 22, 40, 0.88);
  --bg-panel-hover: rgba(15, 30, 55, 0.92);
  --border-color: rgba(100, 160, 220, 0.25);
  --text-primary: #e2e8f0;
  --text-secondary: #94a3b8;
  --text-muted: #64748b;
  --accent: #38bdf8;
  --accent-dim: rgba(56, 189, 248, 0.15);
  --green: #22c55e;
  --yellow: #eab308;
  --red: #ef4444;
  --green-bg: rgba(34, 197, 94, 0.15);
  --yellow-bg: rgba(234, 179, 8, 0.15);
  --red-bg: rgba(239, 68, 68, 0.15);
  --font: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', monospace;
}

html, body {
  height: 100%; width: 100%;
  font-family: var(--font);
  background: var(--bg-dark);
  color: var(--text-primary);
  overflow: hidden;
}

/* ===== Map Container ===== */
#map {
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  z-index: 1;
}

/* ===== Weather Animation Canvas ===== */
#weather-canvas {
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  z-index: 2;
  pointer-events: none;
}

/* ===== Loading Overlay ===== */
#loading-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  z-index: 1000;
  background: var(--bg-dark);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 1.5rem;
  transition: opacity 0.5s ease;
}
#loading-overlay.hidden {
  opacity: 0;
  pointer-events: none;
}
#loading-overlay .spinner {
  width: 48px; height: 48px;
  border: 3px solid var(--border-color);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 1s linear infinite;
}
#loading-overlay .loading-text {
  color: var(--text-secondary);
  font-size: 0.9rem;
}
@keyframes spin { to { transform: rotate(360deg); } }

/* ===== Panels ===== */
.panel {
  position: absolute;
  z-index: 10;
  background: var(--bg-panel);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  border: 1px solid var(--border-color);
  border-radius: 12px;
  padding: 1rem;
  color: var(--text-primary);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
  transition: transform 0.3s ease, opacity 0.3s ease;
}

/* ===== Conditions Panel (top-left) ===== */
#conditions-panel {
  top: 1rem;
  left: 1rem;
  min-width: 260px;
  max-width: 320px;
}
.conditions-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 0.75rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--border-color);
}
.conditions-header h2 {
  font-size: 0.85rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-secondary);
}
.conditions-header .update-time {
  font-size: 0.7rem;
  color: var(--text-muted);
}
.condition-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.35rem 0;
}
.condition-label {
  font-size: 0.8rem;
  color: var(--text-secondary);
}
.condition-value {
  font-size: 0.9rem;
  font-weight: 600;
  font-family: var(--font-mono);
  color: var(--text-primary);
}
.condition-unit {
  font-size: 0.7rem;
  color: var(--text-muted);
  margin-left: 0.25rem;
  font-weight: 400;
}
.wind-arrow {
  display: inline-block;
  margin-right: 0.35rem;
  transition: transform 0.3s ease;
  color: var(--accent);
}

/* ===== Compass Rose Panel (top-right) ===== */
#compass-panel {
  top: 1rem;
  right: 1rem;
  width: 280px;
  display: flex;
  flex-direction: column;
  align-items: center;
}
.compass-title {
  font-size: 0.85rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--text-secondary);
  margin-bottom: 0.75rem;
  width: 100%;
  text-align: center;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--border-color);
}
.compass-rose {
  position: relative;
  width: 220px;
  height: 220px;
  margin: 0.5rem 0;
}
.compass-center {
  position: absolute;
  top: 50%; left: 50%;
  transform: translate(-50%, -50%);
  width: 36px; height: 36px;
  background: var(--bg-dark);
  border: 2px solid var(--border-color);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.65rem;
  color: var(--text-muted);
  z-index: 2;
}
.compass-direction {
  position: absolute;
  display: flex;
  flex-direction: column;
  align-items: center;
  cursor: pointer;
  transition: transform 0.2s ease;
}
.compass-direction:hover {
  transform: scale(1.08);
}
.compass-direction .dir-label {
  font-size: 0.75rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  margin-bottom: 0.15rem;
}
.compass-direction .dir-segment {
  width: 44px;
  height: 8px;
  border-radius: 4px;
  transition: background-color 0.3s ease;
}
.compass-direction .dir-score {
  font-size: 0.6rem;
  font-family: var(--font-mono);
  color: var(--text-muted);
  margin-top: 0.15rem;
}
/* Direction positions — radiating from center */
.compass-direction.dir-N  { top: 2px; left: 50%; transform: translateX(-50%); }
.compass-direction.dir-NE { top: 22px; right: 14px; }
.compass-direction.dir-E  { top: 50%; right: 2px; transform: translateY(-50%); }
.compass-direction.dir-SE { bottom: 22px; right: 14px; }
.compass-direction.dir-S  { bottom: 2px; left: 50%; transform: translateX(-50%); }
.compass-direction.dir-SW { bottom: 22px; left: 14px; }
.compass-direction.dir-W  { top: 50%; left: 2px; transform: translateY(-50%); }
.compass-direction.dir-NW { top: 22px; left: 14px; }

/* Color-coded segments */
.dir-segment.green  { background: var(--green); box-shadow: 0 0 8px rgba(34, 197, 94, 0.4); }
.dir-segment.yellow { background: var(--yellow); box-shadow: 0 0 8px rgba(234, 179, 8, 0.4); }
.dir-segment.red    { background: var(--red); box-shadow: 0 0 8px rgba(239, 68, 68, 0.4); }

/* Direction tooltip */
.compass-tooltip {
  position: absolute;
  bottom: -60px;
  left: 50%;
  transform: translateX(-50%);
  background: var(--bg-panel);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  padding: 0.5rem 0.75rem;
  width: 240px;
  text-align: center;
  font-size: 0.75rem;
  color: var(--text-secondary);
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.2s ease;
}
.compass-tooltip.visible {
  opacity: 1;
}

/* ===== Timeline Panel (bottom) ===== */
#timeline-panel {
  bottom: 1rem;
  left: 50%;
  transform: translateX(-50%);
  width: min(90vw, 600px);
  padding: 0.75rem 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}
.timeline-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.timeline-label {
  font-size: 0.8rem;
  color: var(--text-secondary);
  font-weight: 600;
}
.timeline-time {
  font-size: 0.8rem;
  font-family: var(--font-mono);
  color: var(--accent);
}
.timeline-slider {
  -webkit-appearance: none;
  appearance: none;
  width: 100%;
  height: 6px;
  background: linear-gradient(90deg, var(--accent-dim) 0%, var(--accent) 100%);
  border-radius: 3px;
  outline: none;
  cursor: pointer;
}
.timeline-slider::-webkit-slider-thumb {
  -webkit-appearance: none;
  width: 18px; height: 18px;
  background: var(--accent);
  border-radius: 50%;
  border: 2px solid var(--bg-dark);
  cursor: grab;
  box-shadow: 0 0 8px rgba(56, 189, 248, 0.5);
}
.timeline-slider::-moz-range-thumb {
  width: 18px; height: 18px;
  background: var(--accent);
  border-radius: 50%;
  border: 2px solid var(--bg-dark);
  cursor: grab;
  box-shadow: 0 0 8px rgba(56, 189, 248, 0.5);
}
.timeline-ticks {
  display: flex;
  justify-content: space-between;
  padding: 0 2px;
}
.timeline-tick {
  font-size: 0.6rem;
  color: var(--text-muted);
  font-family: var(--font-mono);
}

/* ===== Boat Marker ===== */
.boat-marker {
  transition: transform 0.5s ease;
}
.boat-marker svg {
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5));
}

/* ===== Info Bar (bottom-left) ===== */
#info-bar {
  position: absolute;
  bottom: 5.5rem;
  left: 1rem;
  z-index: 10;
  background: var(--bg-panel);
  backdrop-filter: blur(12px);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  padding: 0.5rem 0.75rem;
  display: flex;
  gap: 1rem;
  font-size: 0.75rem;
}
.info-item {
  display: flex;
  align-items: center;
  gap: 0.35rem;
}
.info-item .info-label {
  color: var(--text-muted);
}
.info-item .info-value {
  color: var(--text-primary);
  font-family: var(--font-mono);
  font-weight: 600;
}

/* ===== Refresh Button ===== */
#refresh-btn {
  position: absolute;
  bottom: 5.5rem;
  right: 1rem;
  z-index: 10;
  background: var(--bg-panel);
  backdrop-filter: blur(12px);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  padding: 0.5rem 0.75rem;
  color: var(--accent);
  font-size: 0.8rem;
  font-weight: 600;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 0.4rem;
  transition: background 0.2s ease, border-color 0.2s ease;
}
#refresh-btn:hover {
  background: var(--bg-panel-hover);
  border-color: var(--accent);
}
#refresh-btn.loading {
  opacity: 0.6;
  pointer-events: none;
}
#refresh-btn .refresh-icon {
  transition: transform 0.5s ease;
}
#refresh-btn.loading .refresh-icon {
  animation: spin 1s linear infinite;
}

/* ===== Beaufort Scale Legend ===== */
.beaufort-indicator {
  display: inline-flex;
  align-items: center;
  gap: 0.3rem;
  padding: 0.15rem 0.4rem;
  border-radius: 4px;
  font-size: 0.65rem;
  font-weight: 600;
}
.beaufort-0-3 { background: var(--green-bg); color: var(--green); }
.beaufort-4-5 { background: var(--accent-dim); color: var(--accent); }
.beaufort-6-7 { background: var(--yellow-bg); color: var(--yellow); }
.beaufort-8   { background: var(--red-bg); color: var(--red); }

/* ===== Responsive ===== */
@media (max-width: 768px) {
  #conditions-panel {
    top: auto;
    bottom: 6rem;
    left: 1rem;
    right: 1rem;
    max-width: none;
    min-width: 0;
    display: none;
  }
  #conditions-panel.mobile-visible {
    display: block;
  }
  #compass-panel {
    top: 0.5rem;
    right: 0.5rem;
    width: 200px;
    padding: 0.5rem;
  }
  .compass-rose {
