async function testFetchWeatherStructure() {
  // Fetch weather for Marseille — a known coastal location
  const result = await functions.call('fetchWeather', 43.3, 5.37);

  // Verify top-level structure
  assert(result.latitude !== undefined, 'Should have latitude');
  assert(result.longitude !== undefined, 'Should have longitude');
  assert(result.current !== undefined, 'Should have current conditions');
  assert(result.hourly !== undefined, 'Should have hourly forecast');
  assert(Array.isArray(result.hourly), 'Hourly should be an array');
  assert(result.hourly.length > 0, 'Should have at least one hourly entry');

  // Verify current conditions fields
  const curr = result.current;
  assert(typeof curr.temperature === 'number', 'Temperature should be a number');
  assert(typeof curr.windSpeed === 'number', 'Wind speed should be a number');
  assert(typeof curr.windDirection === 'number', 'Wind direction should be a number');
  assert(typeof curr.windGusts === 'number', 'Wind gusts should be a number');
  assert(typeof curr.pressure === 'number', 'Pressure should be a number');
  assert(typeof curr.cloudCover === 'number', 'Cloud cover should be a number');

  // Wind speed should be in knots — reasonable range 0-100
  assert(curr.windSpeed >= 0 && curr.windSpeed < 100, 'Wind speed in knots should be 0-100');

  // Pressure should be in hPa — reasonable range 950-1050
  assert(curr.pressure > 900 && curr.pressure < 1100, 'Pressure in hPa should be 900-1100');

  // Temperature in °C — reasonable range -50 to 60
  assert(curr.temperature > -50 && curr.temperature < 60, 'Temperature in °C should be -50 to 60');

  // Wind direction 0-360 degrees
  assert(curr.windDirection >= 0 && curr.windDirection <= 360, 'Wind direction should be 0-360');

  // Verify hourly entry structure matches current
  const hour = result.hourly[0];
  assert(typeof hour.windSpeed === 'number', 'Hourly wind speed should be a number');
  assert(typeof hour.temperature === 'number', 'Hourly temperature should be a number');
  assert(hour.time !== undefined, 'Hourly entry should have a time');
}
